<template>
  <v-container fluid fill-height align-start ma-0 pa-2>
    <v-row no-gutters>
      <v-col cols="12" sm="12" lg="12" class="pt-2">
        <i-card-top
          class="d-sm-flex"
          headerTitle=""
          :useBtnList="buttonUseList"
          @btnSearch="btnSearch()"
          @btnAdd="btnAdd()"
          @btnSave="btnSave()"
          @btnDelete="btnDelete()"
        >
          <template v-slot:body>
            <v-layout>
              <v-row no-gutters class="pa-2">
                <v-col cols="12" sm="5" md="2" class="pt-2 px-sm-2 px-md-0 py-md-0 ">
                  <v-text-field
                    v-model="korNm"
                    :placeholder="$t('name')"
                    class="mx-1"
                    dense
                    outlined
                    hide-details="auto"
                    @keydown.enter="btnSearch()"
                    clearable
                  />
                </v-col>
                <v-radio-group v-model="delYn" row class="pl-2 pt-2 pt-md-1">
                  <v-radio color="radio" v-for="(item, value) in delYnList" :key="value" :label="$t(item.text)" :v-model="item.value"></v-radio>
                </v-radio-group>
              </v-row>
            </v-layout>
          </template>
        </i-card-top>
      </v-col>
      <v-col cols="12" sm="12" lg="12" class="pa-2 pt-0">
        <i-card-vertical :headerTitle="$t('humanResourceManage')" device="web">
          <template v-slot:body>
            <v-layout column>
              <v-col cols="12" md="12" class="row pa-0">
                <v-col cols="12" lg="12" class="pa-0 ">
                  <DxDataGrid
                    id="hrDataGrid"
                    class="layout-col-height00"
                    width="100%"
                    :ref="dxDataGridRef"
                    :data-source="gridMain"
                    :remote-operations="false"
                    :hover-state-enabled="true"
                    :allow-column-resizing="true"
                    :allow-column-reordering="true"
                    :row-alternation-enabled="true"
                    :column-auto-width="false"
                    :column-hiding-enabled="false"
                    :show-borders="true"
                    :show-row-lines="true"
                    :focused-row-enabled="true"
                    key-expr="id"
                    @editor-preparing="
                      e => {
                        onEditorPreparing(e)
                        onCustomEditorPreparing(e)
                      }
                    "
                    @editing-start="onEditingStart"
                  >
                    <DxSelection select-all-mode="allMode" show-check-boxes-mode="always" mode="multiple" />

                    <DxColumn data-field="compId" data-type="string" :visible="false"> </DxColumn>

                    <DxColumn data-field="esgHrNo" data-type="string" :visible="false"> </DxColumn>

                    <DxColumn data-field="targetId" data-type="string" :visible="false"> </DxColumn>

                    <DxColumn data-field="fileNm" caption="파일명" data-type="string" alignment="left" :visible="false" />

                    <DxColumn data-field="file" caption="파일" data-type="string" alignment="left" :visible="false" />

                    <DxColumn data-field="fileId" caption="파일아이디" data-type="number" alignment="left" :visible="false" />

                    <DxColumn data-field="__fileUpdate__" caption="파일수정여부" data-type="boolean" alignment="left" :visible="false" />

                    <DxColumn data-field="extension" caption="파일" data-type="string" alignment="left" :visible="false" />

                    <DxColumn
                      data-field="korNm"
                      :caption="$t('name')"
                      width="100px"
                      data-type="string"
                      alignment="left"
                      css-class="devest-grid-header-require"
                    >
                    </DxColumn>
                    <DxColumn data-field="jbrp" :caption="$t('position')" width="80px" data-type="string" alignment="left">
                      <DxLookup :data-source="jbrpList" value-expr="minorCd" display-expr="minorNm" />
                    </DxColumn>
                    <DxColumn data-field="sexDiv" :caption="$t('gender')" width="80px" data-type="string" alignment="center">
                      <DxLookup :data-source="sexDivList" />
                    </DxColumn>
                    <DxColumn
                      data-field="birthDt"
                      :caption="$t('birthDate')"
                      width="100px"
                      alignment="center"
                      data-type="date"
                      format="yyyy.MM.dd"
                      edit-cell-template="dateEditor"
                    >
                    </DxColumn>
                    <DxColumn data-field="userCd" :caption="$t('userAccount')" width="110px" data-type="string" alignment="left"> </DxColumn>

                    <DxColumn data-field="sabun" :caption="$t('hrNum')" width="120px" data-type="string" alignment="left"> </DxColumn>

                    <!-- <DxColumn data-field="partCompId" :caption="$t('compName')" width="120px" data-type="string" alignment="left">
                      <DxLookup :data-source="partCompList" value-expr="partCompId" display-expr="partCompNm" />
                    </DxColumn> -->

                    <DxColumn
                      data-field="useYn"
                      data-type="boolean"
                      :caption="$t('use')"
                      alignment="center"
                      width="70px"
                      edit-cell-template="checkBoxEditor"
                    />

                    <DxColumn data-field="groupAuth" data-type="string" width="100px" alignment="center" :caption="$t('authGroup')">
                      <DxLookup :data-source="groupAuthDataSource" value-expr="grpAuthCd" display-expr="grpAuthNm" />
                    </DxColumn>

                    <DxColumn
                      data-field="connStartDt"
                      data-type="date"
                      format="yyyy.MM.dd"
                      width="120px"
                      alignment="center"
                      :caption="$t('connStartDate')"
                      edit-cell-template="dateEditor"
                    />

                    <DxColumn
                      data-field="connEndDt"
                      data-type="date"
                      format="yyyy.MM.dd"
                      width="120px"
                      alignment="center"
                      :caption="$t('connEndDate')"
                      edit-cell-template="dateEditor"
                    />

                    <DxColumn
                      data-field="workingAt"
                      :caption="$t('workStartDate')"
                      width="100px"
                      data-type="string"
                      alignment="center"
                      edit-cell-template="dateEditor"
                    >
                    </DxColumn>

                    <DxColumn
                      data-field="fireAt"
                      :caption="$t('workEndDate')"
                      width="100px"
                      data-type="string"
                      alignment="center"
                      edit-cell-template="dateEditor"
                    >
                    </DxColumn>
                    <template #dateEditor="{ data: cellInfo}">
                      <div>
                        <DxDateBox
                          :value="cellInfo.value"
                          type="date"
                          picker-type="calendar"
                          display-format="yyyy.MM.dd"
                          :use-mask-behavior="true"
                          @value-changed="onDateValueChanged($event, cellInfo)"
                        />
                      </div>
                    </template>
                    <DxColumn data-field="hpNo" :caption="$t('telNo')" width="130px" data-type="string" alignment="left" />
                    <DxColumn data-field="remark" :caption="$t('remark')" width="200px" data-type="string" alignment="left"> </DxColumn>

                    <template #checkBoxEditor="{ data: cellInfo }">
                      <DxCheckBox :value="cellInfo.value == 'Y' ? true : false" :onValueChanged="value => onCheckValueChanged(value, cellInfo)" />
                    </template>
                  </DxDataGrid>
                </v-col>
                <DxFileUploader
                  :ref="dxFileUploaderRef"
                  :multiple="false"
                  :allowed-file-extensions="allowedFileExtensions"
                  upload-mode="useButton"
                  :visible="false"
                  @uploaded="onUploaded"
                  @value-changed="onValueChanged"
                />
              </v-col>
            </v-layout>
          </template>
        </i-card-vertical>
      </v-col>
    </v-row>
  </v-container>
</template>

<script>
import { DxDataGrid, DxColumn, DxSelection, DxLookup, DxEditing, DxFilterRow, DxPatternRule } from 'devextreme-vue/data-grid'
import DxCheckBox from 'devextreme-vue/check-box'
import iCardTop from '@/components/common/iCardTop.vue'
import iCardVertical from '@/components/common/iCardVertical.vue'
import { getHrManage, createNewUserCd, saveHrManage, deleteHrManage } from '@/api/baseManage/esgHRManage'
// import { getCorpManageList } from '@/api/baseManage/corpManage'
import { getGroupData } from '@/api/setting/groupManage'
import notify from 'devextreme/ui/notify'
import { getCommonCode } from '@/api/common/commonApi'
import { DxFileUploader } from 'devextreme-vue/file-uploader'
import baseview from '@/views/base/baseview.vue' //20220414 LYJ base page 추가
import BaseDataGrid from '@/views/base/BaseDataGrid.vue'
import DxDateBox from 'devextreme-vue/date-box'
//import Baseview from '../base/baseview.vue'
import { multiUpload, imageFileTest } from '@/api/baseManage/fileUpload'
import PivotGridDataSource from 'devextreme/ui/pivot_grid/data_source'
import { getExtension, getFilterGroupAuthList } from '@/utils/common.js'
import { AesEncrypt } from '@/utils/aes256' //cyrptojs 적용(aes256)
import { getDateEditorValue } from '@/utils/common.js'
import { validKorName, validSabun, validTell } from '@/utils/validate.js'

export default {
  mixins: [baseview, BaseDataGrid], //20220414 LYJ base page 추가 및 권한 처리
  components: {
    DxDataGrid,
    DxColumn,
    DxSelection,
    DxCheckBox,
    DxLookup,
    DxFileUploader,
    DxDateBox,
    'i-card-vertical': iCardVertical,
    'i-card-top': iCardTop
  },
  data() {
    return {
      dxDataGridRef: 'hrDataGrid',
      dxFileUploaderRef: 'hrFileUploaderRef',
      gridMain: [],
      buttonUseList: [
        'btnSearch', //조회
        'btnAdd', //추가
        'btnSave', //저장
        'btnDelete' //삭제
      ],
      //korNmPattern: /^[ㄱ-ㅎ|가-힣|a-z|A-Z]{2,50}$/i,
      //sabunPattern: /^[ㄱ-ㅎ|가-힣|a-z|A-Z|0-9]{1,20}$/i,
      //phonePattern: /^\d{3}-(\d{4}||\d{3})-\d{4}$/i,
      remarkPattern: /^.{1,400}$/i,
      sexDivList: ['남', '여'],
      jbrpList: [],
      partCompList: [],
      groupAuthDataSource: [],
      korNm: '',
      delYn: 0,
      compId: null,
      delYnList: [
        { text: 'use', value: '0' },
        { text: 'unUse', value: '1' },
        { text: 'delete', value: '2' }
      ],
      isDropZoneActive: false,
      imageSource: '',
      allowedFileExtensions: ['.jpg', '.jpeg', '.gif', '.png'],
      fileData: null,
      aaaa: '',
      uploaderCustomData: { targetType: 'esgHrManage_file', targetId: '' },
      files: [],
      currentCellInfo: null
    }
  },
  beforeMount() {},
  mounted() {
    // var dateBox = new DevExpress.ui.dxDateBox(document.getElementById('dateBox'), {
    //   value: null, // null 값을 허용합니다.
    //   useMaskBehavior: true // 옵션: 입력 마스크 사용
    // })
    this.btnSearch()
  },
  activated() {
    this.setComboBoxData()
  },
  methods: {
    /////////////////////////////////////////////////////////////////
    ////////////////////////파일업로드 methods////////////////////////
    /////////////////////////////////////////////////////////////////
    onUploaded(e) {
      const { file } = e
      const fileReader = new FileReader()
      fileReader.onload = () => {
        this.fileData = fileReader.result
      }
      fileReader.readAsDataURL(file)
      notify(this.$t('파일이 업로드 되었습니다.'), 'success', 300)
    },
    async onValueChanged(e) {
      this.uploaderCustomData = { targetType: this.targetType, targetId: this.targetId }

      var fileReader = new FileReader()
      let file = e.value[0]
      fileReader.readAsDataURL(file)

      fileReader.onload = () => {
        let subFileName = getExtension(file.name)
        let rowIndex = this.currentCellInfo.row.rowIndex
        var arr = fileReader.result.split(',')
        this.GetDataGrid(this.dxDataGridRef).cellValue(rowIndex, 'fileData', arr[1])
        this.GetDataGrid(this.dxDataGridRef).cellValue(rowIndex, 'fileNm', subFileName[0])
        this.GetDataGrid(this.dxDataGridRef).cellValue(rowIndex, 'extension', subFileName[1])
        this.GetDataGrid(this.dxDataGridRef).cellValue(rowIndex, 'file', fileReader.result)
        this.GetDataGrid(this.dxDataGridRef).cellValue(rowIndex, '__fileUpdate__', true)
      }
    },
    uploadClick(e) {
      // 클릭했을 때 해당 열의 데이터를 들고 옴
      this.currentCellInfo = e
      let fileInstance = this.$refs[this.dxFileUploaderRef].instance
      let fileElement = fileInstance.element()
      let uploadButton = fileElement.querySelector(`.dx-button-content`)
      uploadButton.click()
    },
    ///////////////////////////////////////
    /*       Toolbar Button Event        */
    ///////////////////////////////////////
    btnAdd() {
      let newRow = {
        id: this.gridMain.length + 1,
        useYn: 'Y',
        compId: this.comp.id
      }
      Object.defineProperty(newRow, '__created__', { value: true, writable: true, enumerable: true, configurable: true })
      this.GetDataGrid(this.dxDataGridRef).newRow(newRow)
      this.GetDataGrid(this.dxDataGridRef).selectRows(newRow.id, true)
    },
    btnSearch() {
      this.gridInit(this.GetDataGrid(this.dxDataGridRef))

      this.openLoading('searching')

      let searchParams = { korNm: this.korNm,  compId: this.getCompId(), delYn: this.delYn }
      getHrManage(searchParams, true)
        .then(res => {
          this.gridInit(this.GetDataGrid(this.dxDataGridRef))
          this.gridMain = []
          this.gridMain = res.list
          this.FocusFirstRow(this.GetDataGrid(this.dxDataGridRef))
        })
        .finally(() => {
          this.endLoading()
        })
    },
    async btnSave() {
      let selectedRows = await this.GetDataGrid(this.dxDataGridRef).getSelectedRowsData()
      if (selectedRows.length === 0) {
        this.vToastify(this.$t('selectionData'), 'warn')
        return
      }

      this.vToastifyPrompt(
        this.$t('doSaveData'),
        'info',
        //yes action
        current => {
          this.GetDataGrid(this.dxDataGridRef).beginUpdate()
          this.GetDataGrid(this.dxDataGridRef).saveEditData()

          var index = selectedRows.findIndex(element => element.korNm == null || element.korNm.trim() == '')

          if (index >= 0) {
            this.vToastify(`${this.$t('msgReqValidate')} [${this.$t('name')}]`, 'warn')

            this.GetDataGrid(this.dxDataGridRef).endUpdate()
            return
          }

          // 성명, 사번, 휴대전화번호, 비고, 접속허용 시작일/종료일, 입사일/퇴사일 유효성 체크
          var valid = ''
          var patternIndex = selectedRows.findIndex(element => {
            if (!validKorName(element.korNm)) {
              valid = 'korNm'
              return true
            }

            if (element.sabun != null && element.sabun.trim() != '') {
              if (!validSabun(element.sabun)) {
                valid = 'sabun'
                return true
              }
            }

            if (element.hpNo != null && element.hpNo.trim() != '') {
              if (!validTell(element.hpNo)) {
                valid = 'hpNo'
                return true
              }
            }

            if (element.remark != null && element.remark.trim() != '') {
              if (element.remark.match(this.remarkPattern) == null) {
                valid = 'remark'
                return true
              }
            }

            if (element.connStartDt > element.connEndDt) {
              valid = 'connDt'
              return true
            }

            if (element.workingAt > element.fireAt) {
              valid = 'fireAt'
              return true
            }

            return
          })

          if (patternIndex >= 0) {
            this.vToastify(valid == 'korNm' ? this.$t('성명은 한글,영문 2자~50자 이내로 입력하세요.') : this.$t(''), 'warn')
            this.vToastify(valid == 'sabun' ? this.$t('사번은 한글,영문,숫자 20자 이내로 입력하세요.') : this.$t(''), 'warn')
            this.vToastify(valid == 'hpNo' ? this.$t('올바르지 않은 전화번호 형식입니다.') : this.$t(''), 'warn')
            this.vToastify(valid == 'remark' ? this.$t('비고는 200자 이내로 입력하세요.') : this.$t(''), 'warn')
            this.vToastify(valid == 'connDt' ? this.$t('접속허용 종료일은 접속허용 시작일보다 이후여야 합니다.') : this.$t(''), 'warn')
            this.vToastify(valid == 'fireAt' ? this.$t('퇴사일은 입사일보다 이후여야 합니다.') : this.$t(''), 'warn')
            this.GetDataGrid(this.dxDataGridRef).endUpdate()
            return
          }

          let saveData = []
          let fileData = []

          var newRow = selectedRows.findIndex(element => element.__created__ == false && element.connStartDt != null && element.connEndDt != null)
          if (newRow > 0) {
            for (let i = 0; i < selectedRows.length; i++) {
              selectedRows[i].__created__ = true
              //split 처리 시 undefined 처리 조심합시다. by lyj 20230703
              selectedRows[i].connStartDt = selectedRows[i].connStartDt == undefined ? null : selectedRows[i].connStartDt.split('.').join('-')
              selectedRows[i].connEndDt = selectedRows[i].connEndDt == undefined ? null : selectedRows[i].connEndDt.split('.').join('-')
              saveData.push(selectedRows[i])
              if (selectedRows[i].file != null && selectedRows[i].file != '') {
                fileData.push(selectedRows[i])
              }
            }
          }
          for (let i = 0; i < selectedRows.length; i++) {
            selectedRows[i].__created__ = true
            saveData.push(selectedRows[i])
            if (selectedRows[i].file != null && selectedRows[i].file != '') {
              fileData.push(selectedRows[i])
            }
            //퇴사일 등록, 제거시 사용여부 변경
            if (selectedRows[i].fireAt != null && selectedRows[i].fireAt != '') {
              selectedRows[i].useYn = 'N'
            }
          }
          this.openLoading('saving')
          saveHrManage(saveData, true)
            .then(res => {
              if (fileData.length !== 0) {
                this.saveFile(fileData)
              }
              this.gridInit(this.GetDataGrid(this.dxDataGridRef))
              this.btnSearch(false)
            })
            .finally(() => {
              this.GetDataGrid(this.dxDataGridRef).endUpdate()
              this.endLoading()
            })
        },
        null,
        true
      )
    },
    saveFile(selectedRows) {
      return new Promise((resolve, reject) => {
        selectedRows.forEach(element => {
          // string변환된 파일을 다시 File 객체로
          var arr = element.file.split(','),
            mime = arr[0].match(/:(.*?);/)[1],
            bstr = atob(arr[1]),
            n = bstr.length,
            u8arr = new Uint8Array(n)

          while (n--) {
            u8arr[n] = bstr.charCodeAt(n)
          }

          var file = new File([u8arr], `${element.fileNm}.${element.extension}`, { type: mime })
          var formData = new FormData()
          formData.append('files[]', file)

          let fileVO = {
            fileId: null,
            targetId: element.esgHrNo,
            targetType: 'esgHrManage_file',
            useYn: 'Y',
            compId: this.comp.id
          }

          formData.append('FileVO', new Blob([JSON.stringify(fileVO)], { type: 'application/json' }))
          multiUpload(formData, false)
            .then(res => {})
            .finally(() => {
              resolve(true)
            })
        })
      })
    },

    async btnDelete() {
      let createdRows = []
      let selectedRows = []
      var allSelectedRows = await this.GetDataGrid(this.dxDataGridRef).getSelectedRowsData()
      if (allSelectedRows.length === 0) {
        this.vToastify(this.$t('selectionData'), 'warn')
        return
      }
      allSelectedRows.forEach(item => {
        if (item.__created__ == true) createdRows.push(item)
        else selectedRows.push(item)
      })
      if (selectedRows.length === 0) {
        this.deleteCallBack(createdRows)
        return
      }
      this.vToastifyPrompt(
        this.$t('doDeleteData'),
        'info',
        //yes action
        current => {
          this.GetDataGrid(this.dxDataGridRef).beginUpdate()
          this.GetDataGrid(this.dxDataGridRef).saveEditData()
          this.openLoading('deleting')
          deleteHrManage(selectedRows, true)
            .then(res => {
              if (res.success) {
                this.deleteCallBack(allSelectedRows)
              }
            })
            .finally(() => {
              this.GetDataGrid(this.dxDataGridRef).endUpdate()
              this.FocusFirstRow(this.GetDataGrid(this.dxDataGridRef))
              this.endLoading()
            })
        },
        null,
        true
      )
    },
    ///////////////////////////////////////
    /*        DataGrid Event Event       */
    ///////////////////////////////////////
    //행 cell에서 데이터 수정후 저장을 누르면 선택된 데이터가 없다는 메세지가 발생
    //위 문제를 해결하기 위해서 아래 소스코드 구현
    onEditingStart(e) {
      if (e.column.dataField == 'userCd' && e.data.userCd != null) e.cancel = true
      if (e.column.dataField == 'groupAuth' && e.data.__created__ == true) e.cancel = true
      if (e.column.dataField == 'connStartDt' && e.data.__created__ == true) e.cancel = true
      if (e.column.dataField == 'connEndDt' && e.data.__created__ == true) e.cancel = true
      if (e.column.dataField == 'userCd' && e.data.__created__ == true) e.cancel = true
      if (e.column.dataField == 'hpNo' && e.data.__created__ == true) e.cancel = true
    },
    // onEditorPreparing(e) {
    //   if (e.parentType == 'dataRow') {
    //     var valueChanged = this.onCellValueChanged
    //     e.editorOptions.onValueChanged = args => {
    //       if (e.index > -1) valueChanged(args.value, e)
    //     }
    //   }
    // },
    onCustomEditorPreparing(e) {
      if (e.parentType == 'dataRow' && e.type != 'selection') {
        const defaultValueChangeHandler = e.editorOptions.onValueChanged

        if (e.dataField == 'estiCompleteDate') e.editorOptions.readOnly = !e.row.data.planSeq
        else if (e.dataField == 'estiGubn') e.editorOptions.readOnly = !!e.row.data.planSeq

        e.editorOptions.onValueChanged = args => {
          if (e.index > -1) e.component.selectRows(e.row.key, true)
          defaultValueChangeHandler(args)
        }
      }
    },
    onCellValueChanged(value, cellInfo) {
      cellInfo.setValue(value)
      this.GetDataGrid(this.dxDataGridRef).selectRows(cellInfo.row.key, true)
    },

    gridInit() {
      this.GetDataGrid(this.dxDataGridRef).clearSelection()
      this.GetDataGrid(this.dxDataGridRef).option('focusedRowIndex', -1)
      this.GetDataGrid(this.dxDataGridRef).cancelEditData()
    },
    ///////////////////////////////////////
    /*             etc Event             */
    ///////////////////////////////////////
    deleteCallBack(selectedRows) {
      var index = null
      selectedRows.forEach(key => {
        index = this.gridMain.findIndex(obj => obj == key)
        this.gridMain.splice(index, 1)
      })
    },
    clearFilter() {
      this.$refs[this.dxDataGridRef].instance.clearFilter()
    },
    setComboBoxData() {
      Promise.all([
        getCommonCode('C0009'),
        getCommonCode('C0008'),
        getCommonCode('C0014'),
        // getCorpManageList({ compId: this.getCompId() }),
        getGroupData()
      ]).then(response => {
        let failedResponse = response.find(element => !element.success)
        if (failedResponse == null) {
          //	직책/직위
          this.jbrpList = response[1].list.slice()
          this.jbrpList.unshift({ minorCd: '', minorNm: '' })
          // this.partCompList = response[3].list.slice()
          // this.partCompList.unshift({ partCompId: '', partCompNm: '' })

          this.groupAuthDataSource = getFilterGroupAuthList(response[3], this.getCompId())
        }
      })
    },
    onDateValueChanged(event, cellInfo) {
      //날짜 세팅
      let dateFormat = getDateEditorValue(event.value)

      //그리드 삽입
      const cell = this.gridMain[cellInfo.rowIndex]
      cell[cellInfo.column.dataField] = dateFormat
      cellInfo.setValue(dateFormat)
      this.$refs[this.dxDataGridRef].instance.selectRows(cellInfo.row.key, true)
    }
  }
}
</script>

