import request from '@/utils/request'
import { isUseAPI } from '@/utils/check'

export function getHrManage(searchParams, isNotify) {
  return request({
    url: `/api/getHrManage`,
    method: 'POST',
    meta: { apiVersion: '1.0.0' },
    headers: { 'Content-Type': 'application/json;charset=utf8' },
    data: searchParams,
    Notify: { use: isNotify, apitype: 'searched' }
  })
}

export function getHrApi(param) {
  let isTest = false

  if (!isUseAPI() || isTest) {
    return new Promise(function(resolve, reject) {
      let res = getHrApiData
      //console.log('api', res)
      resolve(res.msg)
    })
  }
  return request({
    url: `/api/getHrApi`,
    meta: { apiVersion: '1.0.0' },
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    data: param
  })
}
